# main.py
import os
import uuid
import tempfile
import traceback

from flask import Flask, request, jsonify
from selenium import webdriver
from selenium.webdriver.chrome.options import Options
from PIL import Image
import boto3

S3_BUCKET = os.getenv('SCREENSHOT_BUCKET')
S3_FOLDER = os.getenv('SCREENSHOT_FOLDER', 'screenshots')
AWS_REGION = os.getenv('AWS_REGION', 'us-east-1')
THUMBNAIL_SIZE = (400, 300)
CHROMEDRIVER_PATH = os.getenv('CHROMEDRIVER_PATH', '/usr/bin/chromedriver')

app = Flask(__name__)
s3 = boto3.client('s3', region_name=AWS_REGION)


def _init_driver():
    opts = Options()
    opts.add_argument('--headless')
    opts.add_argument('--no-sandbox')
    opts.add_argument('--disable-gpu')
    opts.add_argument('--disable-dev-shm-usage')
    opts.add_argument('--window-size=1280,720')
    return webdriver.Chrome(executable_path=CHROMEDRIVER_PATH, options=opts)


driver = _init_driver()


def _upload(path, key, mime='image/png'):
    s3.upload_file(path, S3_BUCKET, key, ExtraArgs={'ContentType': mime, 'ACL': 'public-read'})
    return f'https://{S3_BUCKET}.s3.amazonaws.com/{key}'


def _make_thumb(src, dst):
    with Image.open(src) as im:
        im.thumbnail(THUMBNAIL_SIZE)
        im.save(dst, 'PNG')


@app.route('/screenshot', methods=['POST'])
def screenshot():
    data = request.get_json()
    if not data or 'url' not in data:
        return jsonify({'error': 'url parameter missing'}), 400

    url = data['url']
    file_id = str(uuid.uuid4())
    base_key = f'{S3_FOLDER}/{file_id}'
    original_name = f'{file_id}.png'
    thumb_name = f'{file_id}_thumb.png'
    tmp_dir = tempfile.gettempdir()
    original_path = os.path.join(tmp_dir, original_name)
    thumb_path = os.path.join(tmp_dir, thumb_name)

    try:
        driver.set_page_load_timeout(30)
        driver.get(url)
        driver.save_screenshot(original_path)
        _make_thumb(original_path, thumb_path)

        original_url = _upload(original_path, f'{base_key}/{original_name}')
        thumb_url = _upload(thumb_path, f'{base_key}/{thumb_name}')

        return jsonify({'original': original_url, 'thumbnail': thumb_url}), 200
    except Exception as exc:
        traceback.print_exc()
        return jsonify({'error': str(exc)}), 500


if __name__ == '__main__':
    app.run(host='0.0.0.0', port=int(os.getenv('PORT', 8080)))



